import logo from "./logo.svg";
import "./App.css";
import { useState } from "react";
function App() {
    return (
        <div className="App">
            <StepCounter />
            <Counter />
        </div>
    );
}
const Parent = function () {
    const [count, setCount] = useState(0);
};
const StepCounter = function () {
    const [step, setStep] = useState(0);
    const countPlus = function () {
        setStep((s) => s + 1);
    };
    const countMinus = function () {
        if (step <= 0) return;
        setStep((s) => s - 1);
    };
    return (
        <div className="counter-steps">
            <button type="button" onClick={countMinus}>
                -
            </button>
            <span>Step:{step}</span>
            <button type="button" onClick={countPlus}>
                +
            </button>
        </div>
    );
};
const Counter = function () {
    const [count, setCount] = useState(0);
    const countPlus = function () {
        setCount(count + 1);
    };
    const countMinus = function () {
        setCount(count - 1);
    };
    return (
        <div className="counter-steps">
            <button type="button" onClick={countMinus}>
                -
            </button>
            <span>Count:{count}</span>
            <button type="button" onClick={countPlus}>
                +
            </button>
        </div>
    );
};
export default App;
